# Initially generated by GitHub Copilot.
"""Structured change-operation dataclasses for MPP diffs.

Each dataclass represents one atomic change that the diff pipeline can
describe.  Two families:

  Text-level ops   — operate on flattened Unicode body text
  Structural ops   — operate on the EP template tree

The ChangeOps serve as the single intermediate representation between
raw diffing and English rendering, and are also consumed by the
roundtrip verifier (change_ops_apply → mpp_verify).
"""

from dataclasses import dataclass
from typing import Optional

# ── Text-level ops ───────────────────────────────────────────


@dataclass(frozen=True)
class MarkRemoved:
    """A combining mark was removed from a specific letter."""

    char: str
    on_letter: str
    letter_occurrence: int


@dataclass(frozen=True)
class MarkAdded:
    """A combining mark was added to a specific letter."""

    char: str
    on_letter: str
    letter_occurrence: int


@dataclass(frozen=True)
class MarkMoved:
    """The same mark moved from one letter to another."""

    char: str
    from_letter: str
    from_occurrence: int
    to_letter: str
    to_occurrence: int


@dataclass(frozen=True)
class MarkReplaced:
    """One mark was replaced by a different mark on the same letter."""

    on_letter: str
    letter_occurrence: int
    old_char: str
    new_char: str


@dataclass(frozen=True)
class GenericReplace:
    """Both mark and letter differ — a catch-all 1:1 replace."""

    old_char: str
    old_letter: str
    new_char: str
    new_letter: str


@dataclass(frozen=True)
class ComplexReplace:
    """Multi-char replace that cannot be decomposed further."""

    old_qualified: tuple  # tuple of (char, letter, occ) triples
    new_qualified: tuple


@dataclass(frozen=True)
class MarkReordered:
    """Marks on the same letter appear in a different order."""

    chars: tuple  # tuple of mark characters in old order
    on_letter: str
    letter_occurrence: int


@dataclass(frozen=True)
class GrayMaqafAdded:
    """A space was replaced by a gray maqaf."""

    pass


@dataclass(frozen=True)
class GrayMaqafRemoved:
    """A gray maqaf was replaced by a space."""

    pass


@dataclass(frozen=True)
class PaseqAdded:
    """A paseq or legarmeh was added."""

    paseq_type: str  # "legarmeh" or "paseq" or "paseq / legarmeh"
    on_word: Optional[str] = None
    word_occurrence: Optional[int] = None
    old_fragment: Optional[str] = None
    new_fragment: Optional[str] = None


@dataclass(frozen=True)
class PaseqRemoved:
    """A paseq or legarmeh was removed."""

    paseq_type: str
    on_word: Optional[str] = None
    word_occurrence: Optional[int] = None
    old_fragment: Optional[str] = None
    new_fragment: Optional[str] = None


@dataclass(frozen=True)
class GenericTextReplace:
    """Fallback: a text fragment was replaced.

    Passes the roundtrip check trivially (it is literally "replace X
    with Y") but signals that the diff was not fully decomposed.
    """

    old_fragment: str
    new_fragment: str


# ── Structural ops ───────────────────────────────────────────


@dataclass(frozen=True)
class TemplateAdded:
    """A template was added to the EP tree."""

    name: str


@dataclass(frozen=True)
class TemplateRemoved:
    """A template was removed from the EP tree."""

    name: str


@dataclass(frozen=True)
class TemplateRestructured:
    """Internal template structure changed (same names, different arrangement)."""

    pass


# ── Helpers ──────────────────────────────────────────────────


def is_text_op(op):
    """True if *op* is a text-level ChangeOp."""
    return isinstance(
        op,
        (
            MarkRemoved,
            MarkAdded,
            MarkMoved,
            MarkReplaced,
            GenericReplace,
            ComplexReplace,
            MarkReordered,
            GrayMaqafAdded,
            GrayMaqafRemoved,
            PaseqAdded,
            PaseqRemoved,
            GenericTextReplace,
        ),
    )


def is_structural_op(op):
    """True if *op* is a structural ChangeOp."""
    return isinstance(op, (TemplateAdded, TemplateRemoved, TemplateRestructured))
